def parse_duration(s: str) -> int:
    """Преобразует строку вида '2h30m', '45m', '1h', '90s' в количество секунд."""
    if not s:
        raise ValueError("Невалидный ввод: пустая строка")

    total_seconds = 0
    i = 0
    length = len(s)

    while i < length:
        if i + 1 < length and s[i].isdigit() and s[i+1] in 'hms':
            num = int(s[i])
            unit = s[i+1]
            if unit == 'h':
                total_seconds += num * 3600
            elif unit == 'm':
                total_seconds += num * 60
            elif unit == 's':
                total_seconds += num
            else:
                raise ValueError(f"Невалидная единица времени: {unit}")
            i += 2
        elif i < length and s[i].isdigit():
            # Обработка чисел с несколькими цифрами
            num_str = ""
            while i < length and s[i].isdigit():
                num_str += s[i]
                i += 1
            if i < length and s[i] in 'hms':
                num = int(num_str)
                unit = s[i]
                if unit == 'h':
                    total_seconds += num * 3600
                elif unit == 'm':
                    total_seconds += num * 60
                elif unit == 's':
                    total_seconds += num
                else:
                    raise ValueError(f"Невалидная единица времени: {unit}")
                i += 1
            else:
                raise ValueError(f"Невалидный формат: {num_str}")
        else:
            raise ValueError(f"Невалидный символ: {s[i]}")

    return total_seconds
